<?php
 namespace WPAICG\Vector\Providers\Qdrant\Methods; use WPAICG\Vector\Providers\AIPKit_Vector_Qdrant_Strategy; use WP_Error; if (!defined('ABSPATH')) { exit; } function delete_index_logic(AIPKit_Vector_Qdrant_Strategy $strategyInstance, string $index_name): bool|WP_Error { $path = '/collections/' . urlencode($index_name); $response = _request_logic($strategyInstance, 'DELETE', $path); if (is_wp_error($response)) { return $response; } if (isset($response['status']) && $response['status'] === 'ok') { return true; } if (isset($response['result_data']) && $response['result_data'] === true) { return true; } if (isset($response['deleted']) && $response['deleted'] === true) { return true; } return false; }